package worker

import (
	"context"
	"sync"
)

type Pool struct {
	workers int
	tasks   chan func()
	wg      sync.WaitGroup
}

func NewPool(workers int) *Pool {
	p := &Pool{
		workers: workers,
		tasks:   make(chan func(), workers*2),
	}
	for i := 0; i < workers; i++ {
		go p.run()
	}
	return p
}

func (p *Pool) run() {
	for task := range p.tasks {
		task()
		p.wg.Done()
	}
}

func (p *Pool) Submit(ctx context.Context, task func()) {
	p.wg.Add(1)
	select {
	case p.tasks <- task:
	case <-ctx.Done():
		p.wg.Done()
	}
}

func (p *Pool) Wait() {
	p.wg.Wait()
}

