export async function* streamLines(readable) {
  const decoder = new TextDecoder('utf-8');
  let buffer = '';
  for await (const chunk of readable) {
    buffer += decoder.decode(chunk, { stream: true });
    const lines = buffer.split('\n');
    buffer = lines.pop() ?? '';
    for (const line of lines) {
      yield line;
    }
  }
  buffer += decoder.decode();
  if (buffer.length > 0) {
    yield buffer;
  }
}

class RateLimiter {
  constructor(maxRequests, windowMs) {
    this.maxRequests = maxRequests;
    this.windowMs = windowMs;
    this.requests = new Map();
  }

  isAllowed(key) {
    const now = Date.now();
    const timestamps = this.requests.get(key) || [];
    const recent = timestamps.filter(t => t > now - this.windowMs);
    if (recent.length >= this.maxRequests) {
      return false;
    }
    recent.push(now);
    this.requests.set(key, recent);
    return true;
  }
}

export class StateMachine<S extends string, E extends string> {
  private state: S;
  private readonly transitions: Map<string, S>;
  private readonly listeners: Map<S, Array<() => void>>;

  constructor(initial: S, transitions: Array<{ from: S; event: E; to: S }>) {
    this.state = initial;
    this.transitions = new Map();
    this.listeners = new Map();
    for (const { from, event, to } of transitions) {
      this.transitions.set(`${from}:${event}`, to);
    }
  }

  send(event: E): boolean {
    const next = this.transitions.get(`${this.state}:${event}`);
    if (next === undefined) return false;
    this.state = next;
    const listeners = this.listeners.get(next) ?? [];
    for (const listener of listeners) listener();
    return true;
  }

  current(): S {
    return this.state;
  }

  onEnter(state: S, listener: () => void): void {
    if (!this.listeners.has(state)) {
      this.listeners.set(state, []);
    }
    this.listeners.get(state)!.push(listener);
  }
}

