export interface Middleware<Req, Res> {
  (req: Req, res: Res, next: () => Promise<void>): Promise<void>;
}

export class MiddlewareChain<Req, Res> {
  private readonly middlewares: Middleware<Req, Res>[] = [];

  use(middleware: Middleware<Req, Res>): this {
    this.middlewares.push(middleware);
    return this;
  }

  async run(req: Req, res: Res): Promise<void> {
    const dispatch = async (i: number): Promise<void> => {
      if (i >= this.middlewares.length) return;
      await this.middlewares[i](req, res, () => dispatch(i + 1));
    };
    await dispatch(0);
  }
}

from typing import Iterator


def chunks(iterable, size: int) -> Iterator:
    """Yield successive chunks of a given size from an iterable."""
    buffer = []
    for item in iterable:
        buffer.append(item)
        if len(buffer) >= size:
            yield buffer
            buffer = []
    if buffer:
        yield buffer


def flatten(nested):
    """Flatten a nested iterable by one level."""
    for item in nested:
        if isinstance(item, (list, tuple)):
            yield from item
        else:
            yield item

