import (
	"context"
	"errors"
	"time"
)

func withRetry(ctx context.Context, fn func() error, maxAttempts int) error {
	var lastErr error
	backoff := 100 * time.Millisecond

	for attempt := 1; attempt <= maxAttempts; attempt++ {
		if err := fn(); err == nil {
			return nil
		} else {
			lastErr = err
		}

		select {
		case <-ctx.Done():
			return ctx.Err()
		case <-time.After(backoff):
			backoff *= 2
		}
	}
	return errors.New("max attempts reached: " + lastErr.Error())
}

